var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>심도 3등급</color>     \\n이터니움 채굴구역     ","JPN":"<color=#ffd34c>深度レベル3</color>     \\nエタニウム採掘区域     ","ENG":"<color=#ffd34c>Depth 3</color>     \\nEternium Mining Area     ","TWN":"<color=#ffd34c>深度 3等級</color>     \\n永恆之金採集區域"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"망할 업주 놈들. 뭐가 자기들이 손해 보는 장사라는 거야.","JPN":"クソ業者どもめ。やっぱり損するのは俺たちじゃないか。","ENG":"Damn those business owners. How can they be losing any money from this?","TWN":"一群該死的雇主，什麼叫他們在做虧本生意啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"고작 이런 인원만 불러다 놓고 침식체들을 막으라니......","JPN":"この人数で侵食体を防げるはずないだろ……","ENG":"They want us to fend off the C.O. with just this many people?","TWN":"竟然只叫了幾個人，就想阻止侵蝕體……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"탄약 값은 기본 옵션인 줄 아는 건가?","JPN":"弾薬だってタダじゃないんだ。","ENG":"Do they think we all come attached with ammo?","TWN":"他們知道什麼是內定選項嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"계약을 할 땐 원래 정직한 쪽이 손해보는 법이지.","JPN":"契約はいつも正直なヤツが損するものだ。","ENG":"It's the honest party that always loses when signing a contract.","TWN":"簽約的時候，本來就是老實人吃虧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"손해보기 싫으면 자기 몸값에 거품을 깔아두는 편이 좋아.","JPN":"損をしたくないなら、契約の時は大きく出た方がいい。","ENG":"If you don't want to lose anything, you should exaggerate your pay.","TWN":"如果你不想吃虧的話，那最好幫自己的身價灌個水。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"시작부터 본전치기로 부르면 무조건 협상이 불리해지거든.","JPN":"正直な態度は交渉に不利だ。どうせ報酬は値引きされるんだからな。","ENG":"If you start off your deal to break even, you've already lost the deal.","TWN":"不然你一開始就說出底價的話，那談判就會無條件地以不利收場。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"쳇, 난 일을 하러 온 거지, 장사를 배우러 온 게 아니라고.","JPN":"チッ、俺は商売じゃなくて仕事をしに来たんだ。","ENG":"Tsk, I'm here to work, not to conduct business.","TWN":"切，我是來工作，不是來學做生意的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 따지고 보면 이것도 마냥 손해 보는 임무는 아냐.","JPN":"まあ、この任務も損ばかりじゃない。","ENG":"Well honestly, this mission isn't that bad.","TWN":"算了吧。仔細想想，這也不完全是個虧本任務。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"우리가 맡은 임무는 채굴지를 방어하는 거다.","JPN":"俺たちの任務は採掘地の防衛だ。","ENG":"Our mission is to defend the mining site.","TWN":"我們負責的任務是保護採掘場。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 말인 즉, 침식체들 몸에 박힌 이터니움은 계약에 포함되지 않는 우리 몫이란 뜻이지.","JPN":"つまり、侵食体の体に埋まってるエタニウムは契約に含まれないから、俺たちの好きにしていいってことだ。","ENG":"Which means the Eternium embedded in C.O. are not included in the contract. They're all ours.","TWN":"也就是說，侵蝕體體內的永恆之金不在契約範圍內，那就是我們的份了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......당신은 누구지? 그런 정보를 굳이 나한테 줘서 득 될 거라도 있나?","JPN":"……あんた何なんだ？俺に情報を与えて、あんたに何の得がある？","ENG":"And who might you be? Do you get anything out of telling me this information?","TWN":"……你是誰啊？特別告訴我這個情報，是能得到什麼好處嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 침식체의 이터니움을 추출을 하는 것도 집중이 필요한 작업이라고.","JPN":"侵食体からエタニウムを抽出するには、慎重に作業しなければならない。","ENG":"Look, extracting Eternium from C.O. requires a lot of concentration.","TWN":"因為你看，提取侵蝕體體內的永恆之金，是個需要集中精神的作業。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"내가 작업을 하는 동안 뒤를 맡길 수 있는 협력자 정도는 있어야지 않겠어?","JPN":"だから作業をする間、俺を守ってくれるやつが必要だ。","ENG":"I could use an ally to watch my back while I work my magic.","TWN":"我在幹活的時候，總得把背後交給某個幫手吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"8대 2.","JPN":"8対2。","ENG":"80-20.","TWN":"8比2"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......장비가 첨단이라서 몰라 뵀는데, 수완은 영 초짜인 친구일세.","JPN":"……最新装備で身を固めてたから気づかなかったが、完全に素人だな。","ENG":"I had no idea you were such a novice with all your fancy tech gear.","TWN":"……一開始因為你的裝備都很高科技，所以沒看出來，但你真的是隻菜雞呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"7대 3. 당신 몫까지 침식체들을 막는 거니까 이 정도는 받아야지.","JPN":"7対3。あんたの分まで侵食体を防ぐんだから妥当だろ。","ENG":"70-30. I deserve at least this much since I'm carrying the burden of stopping the C.O.","TWN":"7比3，因為我連你的侵蝕體都要一起對付了，這樣你不接受不行吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"초짜인데다 욕심도 많군.","JPN":"素人の上に欲張りか。","ENG":"A greedy novice I see.","TWN":"不但是個菜雞，還很貪心呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이 바닥도 노하우가 필요한 전문일터라고.","JPN":"これもノウハウが必要な専門職だ。","ENG":"You do realize this field of work requires specialized knowledge?","TWN":"這圈子是需要門道的專業職場。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그런 곳에서 뭔가를 배울 때는 그만한 투자를 해야 한다고 집안 어른들에게 배우지 않았어?","JPN":"こういう業界で何かを学ぶときは、それ相応の投資が必要だって、親から教わらなかったのか？","ENG":"Didn't your parents teach you to invest first if you want to learn something like this?","TWN":"在這種地方要學什麼東西的時候，就必須做相應的投資才行，家裡的長輩沒教過你嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......형이 하던 것과 비슷한 잔소릴 하는군.","JPN":"……あんた、兄貴と似たようなことを言うな。","ENG":"You sound just like my brother.","TWN":"……老哥好像有說過類似的話呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋은 형을 뒀는걸.","JPN":"そりゃ、いい兄貴だな。","ENG":"Then you must have a great brother.","TWN":"真是個好哥哥。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"설교는 그쯤이면 충분해, 고참. 그럼 내가 손해 보는 셈 치고 5대 5로 하지.","JPN":"説教はもう十分だ。俺の損にはなるが5対5でどうだ？","ENG":"That's enough preaching. I'll just take the loss and we'll make it 50-50.","TWN":"說教說夠了吧。那就當我吃虧，5比5對分好了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋아. 그럼 내 몫까지 잘 막고 있으라고.","JPN":"よし。それじゃあ、俺の分までしっかり防いでくれ。","ENG":"Done deal. Try to have fun while blocking my share.","TWN":"很好，那我的那份就交給你了，好好擋住它們啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MINER_NPC_NULL_NULL","text":{"KOREA":"어이, 용병들! 작업종료다! 철수할 준비해!","JPN":"おい、傭兵ども！作業は終了だ！撤退するぞ！","ENG":"Alright, mercs! Wrap it up! Prepare to withdraw!","TWN":"喂，傭兵們！作業結束了！準備撤退！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"꽤 하는군. 드론하고 콤비가 잘 맞던걸?","JPN":"なかなかだった。ドローンともよく息が合っていた。","ENG":"Not bad. You work really well with your drone.","TWN":"做得很好啊，和無人機的配合也很有默契嘛？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......이제 내 몫을 받고 싶은데.","JPN":"……俺の分はどうした？","ENG":"I'll take my half now.","TWN":"……現在我想要拿我的那份。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"안 떼먹으니까 너무 정 없게 굴지 말라고. 이 바닥은 신뢰가 생명이거든.","JPN":"ちゃんと渡すから心配するな。この業界は信用が命だからな。","ENG":"I'm not going to scam you out of it, chill out. You need trust in this field of work.","TWN":"我又不會私吞，別這麼沒有人情味，一直催我。在這圈子，信用就是生命呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"자, 이거 받아.","JPN":"ほら、お前の分だ。","ENG":"Here's your share.","TWN":"來，接住。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이렇게나 많아? 이 정도 양이라면...... 적자를 면하는 정도가 아닌데?","JPN":"こんなに多いのか？この量なら、黒字どころか……","ENG":"This much? With all of these... I think I'll be shaving off more than my losses.","TWN":"這麼多？這個數量的話……應該可以脫離赤字了吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......난 존 메이슨이라고 한다. 그쪽은?","JPN":"……俺はジョン・メイソンだ。あんたは？","ENG":"I'm John Mason. You are?","TWN":"我叫約翰·梅森。你呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"에디 피셔다.","JPN":"エディー・フィシャーだ。","ENG":"Eddie Fisher.","TWN":"艾迪·費舍爾。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이제서야 통성명이라니. 역시 용병의 인연은 돈이 전부라는 말이 틀린 게 아닌 걸?","JPN":"やっと自己紹介か。やはり傭兵の縁は、金で繋がってるって話は嘘じゃないな。","ENG":"We finally introduce ourselves. I guess it is true that money is everything in a mercenary's relationship.","TWN":"到現在才互報姓名，說傭兵之間的緣分全靠金錢，這句話果然沒錯啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"섭섭했다면 미안하군.","JPN":"悪かったな。","ENG":"I'm sorry if I disappointed you.","TWN":"如果造成你的不快，那真是抱歉啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 용병이지만, 용병은 섣불리 믿을만한 게 못돼서 말이지.","JPN":"俺も傭兵だが、傭兵は信用できないんだ。","ENG":"I'm a mercenary myself, but it's just hard to believe our own.","TWN":"雖然我也是個傭兵，但我可不會隨便相信傭兵。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"좋은 마음가짐이야. 앞으로 크게 될 진 모르겠지만 적어도 자기 앞가림은 문제 없겠어.","JPN":"いい心がけだ。これからどう成長するかわからないが、しぶとく生き残りそうだな。","ENG":"That's a good attitude. I'm not sure how well you'll do in the future, but I think you'll manage.","TWN":"心態不錯。雖然不保證你能賺大錢，但要照顧自己應該沒問題吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 전투 드론은...... 당신이 직접 만든 건가?","JPN":"あの戦闘ドローンは……お前が作ったのか？","ENG":"That combat drone... Did you make it yourself?","TWN":"那個戰鬥無人機……是你自己做的嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"형이 설계하고 내가 만든 거야.","JPN":"兄貴が設計して、俺が作ったんだ。","ENG":"My brother designed it and I built it.","TWN":"是我老哥設計然後我做的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아직 프로토타입이지만 이걸 바탕으로 더 끝내주는 걸 만들 예정이지.","JPN":"まだプロトタイプだがこれを基にして、さらにすごいやつを作るつもりだ。","ENG":"It's still a prototype, but I'm going to make something bigger based off of this.","TWN":"雖然還只是原型，但我打算以這個為基礎，做一個更棒的傢伙出來。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래? 형제가 나란히 훌륭한 기술자인가보네.","JPN":"そうか。兄弟そろって、優秀なメカニックなんだな。","ENG":"Really? Looks like you're both great engineers.","TWN":"是嗎？看來你們兄弟倆都是很優秀的技術員啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"나중에 신형이 나오면 나도 한 대 살 수 있었으면 좋겠군.","JPN":"新型の開発に成功したら、一台買えるか？","ENG":"I'd love to buy this one once you build the new one.","TWN":"到時候新型機出來的話，我也能買一台就好了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"파는 물건은 아니야.","JPN":"売り物じゃないんだ。","ENG":"It's not for sale.","TWN":"那不是拿來賣的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만...... 그쪽이 가진 장비들을 개조해주는 정도는 가능하겠지.","JPN":"けど……あんたの装備くらいは改造してやれる。","ENG":"But... I could modify some of your gear if you want.","TWN":"不過……改造你的裝備那倒是還可以。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"물론 비용은 받겠지만, 이것도 아무에게나 해주는 서비스는 아니거든.","JPN":"もちろん金は取るが、これもかなり特別なサービスなんだぞ。","ENG":"It'll cost you, but I don't offer my service to anyone.","TWN":"當然，我會收費，這可不是對誰都能提供的服務。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"자부심이 철철 넘치시는군.","JPN":"自信満々だな。","ENG":"You must be proud of your skills.","TWN":"看來你自信心破表啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"서비스는 다음에 기회가 되면 받도록 하지. 나도 지금 여윳돈이 그리 많지는 않아서.","JPN":"そのサービスは、今度にしておく。俺も今は余裕がないんでな。","ENG":"I'll have to take a rain check on that offer. I don't really have enough saved up at the moment.","TWN":"這服務我就下次再說吧，我現在也沒那麼多閒錢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그럼 살아서 만나지.","JPN":"……それじゃあ、生きてまた会おう。","ENG":"Then let's meet again alive.","TWN":"……那我們活著再見吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그래, 살아서 보자고.","JPN":"……ああ、生きてたらな。","ENG":"Yes, let's do that.","TWN":"……是啊，活著再見。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};